<template><view class="page"><PageState :loading="loading" :empty="items.length===0" empty-text="购物车还是空的"><view class="card" v-for="i in items" :key="i.cartId"><view class="cart-row"><checkbox :checked="i.selected" @click="toggle(i)"/><view class="pic"></view><view class="info"><text class="title">{{i.productName}}</text><text class="price">¥{{i.price}}</text><view class="qty"><button @click="changeQty(i,-1)">-</button><text>{{i.quantity}}</text><button @click="changeQty(i,1)">+</button></view></view><text class="del" @click="remove(i)">删除</text></view></view></PageState><view class="bottom"><text>合计：<text class="price">¥{{total}}</text></text><button class="primary" @click="checkout">结算</button></view></view></template>
<script setup lang="ts">import { computed, ref } from 'vue';import { onShow } from '@dcloudio/uni-app';import PageState from '@/components/PageState/PageState.vue';import { cartApi } from '@/services/cart';import { listOf, money } from '@/utils/format';const items=ref<any[]>([]),loading=ref(false);const total=computed(()=>money(items.value.filter(i=>i.selected).reduce((s,i)=>s+Number(i.price||0)*Number(i.quantity||1),0)));async function load(){loading.value=true;try{const res=await cartApi.list();items.value=listOf(res.data)}finally{loading.value=false}}async function toggle(i:any){i.selected=!i.selected;await cartApi.select(i.cartId,i.selected)}async function changeQty(i:any,n:number){i.quantity=Math.max(1,Number(i.quantity)+n);await cartApi.updateQuantity(i.cartId,i.quantity)}async function remove(i:any){await cartApi.remove(i.cartId);load()}function checkout(){const ids=items.value.filter(i=>i.selected).map(i=>i.cartId);if(!ids.length){uni.showToast({title:'请选择商品',icon:'none'});return}uni.navigateTo({url:'/pages/checkout/index?ids='+ids.join(',')})}onShow(load)</script>
<style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;padding-bottom:130rpx}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.cart-row{display:flex;gap:18rpx;align-items:center}.pic{width:130rpx;height:130rpx;border-radius:12rpx;background:#ead7b8}.info{flex:1}.title{display:block;font-weight:900}.price{color:#b97700;font-weight:900}.qty{display:flex;gap:18rpx;align-items:center;margin-top:12rpx}.qty button{width:54rpx;height:46rpx;line-height:46rpx;border:0}.del{color:#d64535}.bottom{position:fixed;bottom:0;left:0;right:0;background:#fff;padding:20rpx;display:flex;justify-content:space-between;align-items:center}.bottom button{width:220rpx;height:82rpx;line-height:82rpx;border:0;border-radius:999rpx}.primary{background:#b97700;color:#fff}button:after{border:0}</style>
